/* selectCompanyList */ SELECT com.company_id, com.biz_no, com.company_nm, com.representative_nm, com.biz_type, com.biz_item, com.address, com.tel_no, com.fax_no, com.email, com.rmk, com.shipper_yn, com.region_cd, cod1.code_nm as region_nm ,com.region_dtl_cd, cod2.code_nm as region_dtl_nm, com.manager_nm, com.manager_tel_no, com.reg_id, com.reg_dt, com.chg_id, com.chg_dt, com.del_yn, shi.shipper_id, shi.use_yn, shi.shipper_cd, cod3.code_nm AS shipper_nm, shi.vat_yn, shi.bill_stdr_cd, shi.taxbil_output_yn, shi.communication_fee, shi.untpc, shi.weight_untpc, shi.bill_company_id, bc.company_nm as bill_company_nm, shi.excclc_company_id, com1.company_nm as excclc_company_nm, shi.bill_char_cd, cdr.delivery_route_id, cdr.delivery_route_cd, dr.delivery_route_nm, dr.delivery_route_nm AS delivery_route_label FROM company com LEFT JOIN shipper shi ON shi.company_id = com.company_id AND shi.del_yn = 'N' AND com.shipper_yn = 'Y' LEFT JOIN bill_company bc ON bc.bill_company_id = shi.bill_company_id AND bc.del_yn = 'N' LEFT JOIN company_delivery_route cdr ON cdr.company_id = com.company_id AND cdr.del_yn = 'N' LEFT JOIN delivery_route dr ON dr.delivery_route_id = cdr.delivery_route_id AND dr.del_yn = 'N' LEFT JOIN company com1 ON com1.company_id = shi.excclc_company_id AND com1.del_yn = 'N' LEFT JOIN code cod1 ON cod1.code_val = com.region_cd AND cod1."type" = 'REGION_TYPE' AND cod1.del_yn = 'N' LEFT JOIN code cod2 ON cod2.code_val = com.region_dtl_cd AND cod2.parnts_code_val = com.region_cd AND cod2."type" = 'REGION_DTL_TYPE' AND cod2.del_yn = 'N' LEFT JOIN code cod3 ON cod3.CODE_VAL = shi.shipper_cd AND cod3.del_yn = 'N' WHERE 1=1
AND com.company_id = #{companyId}
AND ( com.company_nm ILIKE CONCAT('%', #{companyNm}, '%') OR ( LENGTH(regexp_replace(#{companyNm}, '[^0-9]', '', 'g')) = 4 AND ( RIGHT(regexp_replace(COALESCE(com.tel_no, ''), '[^0-9]', '', 'g'), 4) = regexp_replace(#{companyNm}, '[^0-9]', '', 'g') OR RIGHT(regexp_replace(COALESCE(com.manager_tel_no, ''), '[^0-9]', '', 'g'), 4) = regexp_replace(#{companyNm}, '[^0-9]', '', 'g') ) ) )
AND com.tel_no like CONCAT('%',#{telNo},'%')
AND com.shipper_yn = #{shipperYn}
AND shi.shipper_cd = #{shipperCd}
AND com.region_cd = #{regionCd}
AND shi.bill_company_id = #{billCompanyId}
AND com.company_id = #{userCompanyId}
ORDER BY com.del_yn, com.company_id DESC

SELECT com.company_id, com.biz_no, com.company_nm, com.representative_nm, com.biz_type, com.biz_item, com.address, com.tel_no, com.fax_no, com.email, com.rmk, com.shipper_yn, com.region_cd, cod1.code_nm as region_nm ,com.region_dtl_cd, cod2.code_nm as region_dtl_nm, com.manager_nm, com.manager_tel_no, com.reg_id, com.reg_dt, com.chg_id, com.chg_dt, com.del_yn, shi.shipper_id, shi.use_yn, shi.shipper_cd, cod3.code_nm AS shipper_nm, shi.vat_yn, shi.bill_stdr_cd, shi.taxbil_output_yn, shi.communication_fee, shi.untpc, shi.weight_untpc, shi.bill_company_id, bc.company_nm as bill_company_nm, shi.excclc_company_id, com1.company_nm as excclc_company_nm, shi.bill_char_cd, cdr.delivery_route_id, cdr.delivery_route_cd, dr.delivery_route_nm, dr.delivery_route_nm AS delivery_route_label FROM company com LEFT JOIN shipper shi ON shi.company_id = com.company_id AND shi.del_yn = 'N' AND com.shipper_yn = 'Y' LEFT JOIN bill_company bc ON bc.bill_company_id = shi.bill_company_id AND bc.del_yn = 'N' LEFT JOIN company_delivery_route cdr ON cdr.company_id = com.company_id AND cdr.del_yn = 'N' LEFT JOIN delivery_route dr ON dr.delivery_route_id = cdr.delivery_route_id AND dr.del_yn = 'N' LEFT JOIN company com1 ON com1.company_id = shi.excclc_company_id AND com1.del_yn = 'N' LEFT JOIN code cod1 ON cod1.code_val = com.region_cd AND cod1."type" = 'REGION_TYPE' AND cod1.del_yn = 'N' LEFT JOIN code cod2 ON cod2.code_val = com.region_dtl_cd AND cod2.parnts_code_val = com.region_cd AND cod2."type" = 'REGION_DTL_TYPE' AND cod2.del_yn = 'N' LEFT JOIN code cod3 ON cod3.CODE_VAL = shi.shipper_cd AND cod3.del_yn = 'N'
AND com.company_id = #{companyId}
AND ( com.company_nm ILIKE CONCAT('%', #{companyNm}, '%') OR ( LENGTH(regexp_replace(#{companyNm}, '[^0-9]', '', 'g')) = 4 AND ( RIGHT(regexp_replace(COALESCE(com.tel_no, ''), '[^0-9]', '', 'g'), 4) = regexp_replace(#{companyNm}, '[^0-9]', '', 'g') OR RIGHT(regexp_replace(COALESCE(com.manager_tel_no, ''), '[^0-9]', '', 'g'), 4) = regexp_replace(#{companyNm}, '[^0-9]', '', 'g') ) ) )
AND com.tel_no LIKE CONCAT('%', #{telNo}, '%')
AND com.shipper_yn = #{shipperYn}
AND shi.shipper_cd = #{shipperCd}
AND com.region_cd = #{regionCd}
AND shi.bill_company_id = #{billCompanyId}
AND com.company_id = #{userCompanyId}
ORDER BY ${orderBy} LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1)
FROM company com
LEFT JOIN shipper shi ON shi.company_id = com.company_id AND shi.del_yn = 'N' AND com.shipper_yn = 'Y'


        AND com.company_id = #{companyId}




        AND (
        com.company_nm ILIKE CONCAT('%', #{companyNm}, '%')
        OR (
        LENGTH(regexp_replace(#{companyNm}, '[^0-9]', '', 'g')) > 0
        AND (
        regexp_replace(COALESCE(com.tel_no, ''), '[^0-9]', '', 'g')
        LIKE CONCAT('%', regexp_replace(#{companyNm}, '[^0-9]', '', 'g'), '%')
        OR regexp_replace(COALESCE(com.manager_tel_no, ''), '[^0-9]', '', 'g')
        LIKE CONCAT('%', regexp_replace(#{companyNm}, '[^0-9]', '', 'g'), '%')
        )
        )
        )



        AND com.tel_no LIKE CONCAT('%', #{telNo}, '%')



        AND com.shipper_yn = #{shipperYn}



        AND shi.shipper_cd = #{shipperCd}



        AND com.region_cd = #{regionCd}


        AND shi.bill_company_id = #{billCompanyId}


        AND com.company_id = #{userCompanyId}

mapper.insert:
    	/* insertCompanyDeleteBackup */
		INSERT INTO company_delete_tmp (company_id, data_json, reg_id, chg_id)
		SELECT
		    c.company_id
		    , jsonb_build_object(
		        'company', to_jsonb(c),
		        'shipper', COALESCE(
		            (SELECT jsonb_agg(to_jsonb(s)) FROM shipper s WHERE s.company_id = c.company_id),
		            '[]'::jsonb
		        ),
		        'delivery_routes', COALESCE(
		            (SELECT jsonb_agg(to_jsonb(dr)) FROM company_delivery_route dr WHERE dr.company_id = c.company_id),
		            '[]'::jsonb
		        )
		    )
		    , #{memberInfo.memberId}
		    , #{memberInfo.memberId}
		FROM company c
		WHERE c.company_id = #{param.companyId}
